var skillName = "active.mod.launch_mortar_smoke_autoloader";
var skillOpt = Templates.All<SkillTemplate>().FirstOrDefault(s => s.name == skillName);
Assert.NotNull(skillOpt, $"Skill/Perk '{skillName}' should exist");
skillOpt

var handlers = skillOpt.EventHandlers;
Assert.NotNull(handlers, "EventHandlers should not be null");
Assert.True(handlers.Count > 0, "Should have at least one EventHandler");
var handler = handlers.FirstOrDefault(h => h._type == "SetAnimatorTrigger");
Assert.NotNull(handler, $"Should find SetAnimatorTrigger EventHandler");
handler

var fieldValue = handler.Parameter;
Assert.NotNull(fieldValue, "Parameter should be populated");
fieldValue
